 35‚Üí  const feeLabel = (() => {
 36‚Üí    const parts: string[] = [];
 37‚Üí    if (feeBps !== null && feeBps > 0) parts.push(`${(feeBps / 100).toFixed(0)}%`);
 38‚Üí    if (feeFlat !== null && feeFlat > 0) parts.push(formatMoney(feeFlat));
 39‚Üí    return parts.length > 0 ? parts.join(" + ") : null;
 40‚Üí  })();
 41‚Üí
 42‚Üí  const nextLabel = useMemo(() => {
 43‚Üí    const tz = plan.pickup_location.timezone || "UTC";
