 85‚Üí    }
 86‚Üí  }
 87‚Üí
 88‚Üí  async function completeSubscribe() {
 89‚Üí    if (!checkout) return;
 90‚Üí    try {
 91‚Üí      const res = await buyerApi.subscribeToPlan(plan.id, {
 92‚Üí        payment_intent_id: checkout.mode === "payment_intent" ? checkout.id : undefined,
 93‚Üí        setup_intent_id: checkout.mode === "setup_intent" ? checkout.id : undefined,
 94‚Üí        buyer: {
 95‚Üí          email,
 96‚Üí          name: name || null,
 97‚Üí          phone: phone || null,
 98‚Üí        },
 99‚Üí      });
100‚Üí      subscriptionToken.set(res.subscription.id, res.subscription.buyer_token);
101‚Üí      orderToken.set(res.first_order.id, res.first_order.buyer_token);
102‚Üí      setDone(res);
103‚Üí      setCheckout(null);
104‚Üí      showToast({ kind: "success", message: "Subscription started." });
105‚Üí    } catch {
106‚Üí      // Card is already authorized ‚Äî keep checkout state so user can retry
107‚Üí      // without re-authorizing their card.
108‚Üí      setError(
109‚Üí        "Your card was authorized, but we couldn\u2019t create your subscription. " +
110‚Üí        "Please tap \u201cAuthorize card\u201d again to retry. " +
111‚Üí        "If the problem persists, contact support \u2014 your card will not be charged.",
112‚Üí      );
113‚Üí      // Re-throw with sentinel so AuthorizeCard resets submitting without
