278‚Üí                type="tel"
279‚Üí                value={phone}
280‚Üí                onChange={(e) => setPhone(e.target.value)}
281‚Üí                disabled={formLocked}
282‚Üí                placeholder="(555) 555-1234"
283‚Üí              />
284‚Üí            </label>
285‚Üí          </div>
286‚Üí        ) : (
287‚Üí          <button
288‚Üí            type="button"
289‚Üí            className="text-left text-xs font-medium text-[color:var(--lr-muted)] hover:text-[color:var(--lr-ink)] transition-colors"
290‚Üí            onClick={() => setShowOptional(true)}
291‚Üí          >
292‚Üí            + Add name / phone (optional)
293‚Üí          </button>
294‚Üí        )}
295‚Üí
296‚Üí        <button
297‚Üí          type="submit"
298‚Üí          className={`lr-btn lr-btn-primary inline-flex items-center justify-center px-4 py-2 text-sm font-semibold disabled:opacity-50${checkout ? " cursor-not-allowed" : ""}`}
299‚Üí          disabled={submitting || !email.trim() || !plan.is_live || !paymentsReady || !!checkout}
