306‚Üí                ? "Complete payment below"
307‚Üí                : submitting
308‚Üí                  ? "Starting\u2026"
309‚Üí                  : "Start subscription"}
310‚Üí        </button>
311‚Üí        {checkout ? (
312‚Üí          <AuthorizeCard
313‚Üí            clientSecret={checkout.client_secret}
314‚Üí            submitting={submitting}
315‚Üí            setSubmitting={setSubmitting}
316‚Üí            setError={setError}
317‚Üí            onAuthorized={completeSubscribe}
318‚Üí            mode={checkout.mode}
319‚Üí          />
