321‚Üí          <div className="text-xs text-[color:var(--lr-muted)]">
322‚Üí            Cancel/skip/refunds follow the cutoff policy.{" "}
323‚Üí            <Link className="underline" href="/policies">
324‚Üí              Policies
325‚Üí            </Link>
326‚Üí            .
327‚Üí          </div>
328‚Üí        )}
329‚Üí      </form>
330‚Üí    </section>
331‚Üí  );
332‚Üí}
