  1‚Üí"use client";
  2‚Üí
  3‚Üíimport { Suspense, useEffect, useState, useCallback, useRef } from "react";
  4‚Üíimport Link from "next/link";
  5‚Üíimport { useSearchParams } from "next/navigation";
  6‚Üíimport { api, type Store, type PlacePrediction } from "@/lib/api";
  7‚Üíimport { session } from "@/lib/session";
  8‚Üíimport { StoreCard } from "@/components/store-card";
  9‚Üí
 10‚Üíconst RADIUS_OPTIONS = [
 11‚Üí  { label: "10 mi", km: 16 },
 12‚Üí  { label: "25 mi", km: 40 },
 13‚Üí  { label: "50 mi", km: 80 },
 14‚Üí  { label: "100 mi", km: 161 },
 15‚Üí] as const;
 16‚Üí
 17‚Üíconst DEFAULT_RADIUS_KM = 40;
 18‚Üí
 19‚Üíexport default function StoresPage() {
 20‚Üí  return (
 21‚Üí    <Suspense>
 22‚Üí      <StoresContent />
 23‚Üí    </Suspense>
 24‚Üí  );
 25‚Üí}
 26‚Üí
 27‚Üífunction StoresContent() {
 28‚Üí  const searchParams = useSearchParams();
 29‚Üí  const isDemo = searchParams.get("demo") === "true";
 30‚Üí
 31‚Üí  const [stores, setStores] = useState<Store[] | null>(null);
 32‚Üí  const [error, setError] = useState<string | null>(null);
 33‚Üí  const [loading, setLoading] = useState(true);
 34‚Üí  const [hasLocation, setHasLocation] = useState(false);
 35‚Üí  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(
 36‚Üí    null,
 37‚Üí  );
 38‚Üí  const [radiusKm, setRadiusKm] = useState(DEFAULT_RADIUS_KM);
 39‚Üí  const [locationLabel, setLocationLabel] = useState<string | null>(null);
 40‚Üí  const [searchQuery, setSearchQuery] = useState("");
 41‚Üí  const [searchError, setSearchError] = useState<string | null>(null);
 42‚Üí  const [notifyEmail, setNotifyEmail] = useState("");
 43‚Üí  const [notifySubmitted, setNotifySubmitted] = useState(false);
 44‚Üí
 45‚Üí  // Autocomplete state
 46‚Üí  const [predictions, setPredictions] = useState<PlacePrediction[]>([]);
 47‚Üí  const [showDropdown, setShowDropdown] = useState(false);
 48‚Üí  const [activeIndex, setActiveIndex] = useState(-1);
 49‚Üí  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 50‚Üí  const wrapperRef = useRef<HTMLDivElement>(null);
 51‚Üí
 52‚Üí  const fetchStores = useCallback(
 53‚Üí    async (loc?: { lat: number; lng: number } | null, radius?: number) => {
 54‚Üí      setLoading(true);
 55‚Üí      setError(null);
 56‚Üí      try {
 57‚Üí        const token = isDemo ? session.getToken() ?? undefined : undefined;
 58‚Üí        const opts = loc
 59‚Üí          ? { lat: loc.lat, lng: loc.lng, radius_km: radius ?? radiusKm, demo: isDemo || undefined, token }
 60‚Üí          : isDemo ? { demo: true, token } : undefined;
 61‚Üí        const data = await api.listStores(opts);
 62‚Üí        setStores(data);
 63‚Üí        setHasLocation(!!loc);
 64‚Üí      } catch (e) {
 65‚Üí        setError(e instanceof Error ? e.message : "Unknown error");
 66‚Üí      } finally {
 67‚Üí        setLoading(false);
 68‚Üí      }
 69‚Üí    },
 70‚Üí    [radiusKm, isDemo],
 71‚Üí  );
 72‚Üí
 73‚Üí  // Initial load: show all stores; detect geolocation silently for search
 74‚Üí  useEffect(() => {
 75‚Üí    fetchStores();
 76‚Üí
 77‚Üí    if (navigator.geolocation) {
 78‚Üí      navigator.geolocation.getCurrentPosition(
 79‚Üí        (pos) => {
 80‚Üí          setCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
 81‚Üí        },
 82‚Üí        () => {},
 83‚Üí        { timeout: 5000 },
 84‚Üí      );
 85‚Üí    }
 86‚Üí    // eslint-disable-next-line react-hooks/exhaustive-deps
 87‚Üí  }, []);
 88‚Üí
 89‚Üí  // Re-fetch when radius changes (only if we have coords)
 90‚Üí  useEffect(() => {
 91‚Üí    if (coords) {
 92‚Üí      fetchStores(coords, radiusKm);
 93‚Üí    }
 94‚Üí    // eslint-disable-next-line react-hooks/exhaustive-deps
 95‚Üí  }, [radiusKm]);
 96‚Üí
 97‚Üí  // Close dropdown on outside click
 98‚Üí  useEffect(() => {
 99‚Üí    function handleClick(e: MouseEvent) {
100‚Üí      if (
101‚Üí        wrapperRef.current &&
102‚Üí        !wrapperRef.current.contains(e.target as Node)
103‚Üí      ) {
104‚Üí        setShowDropdown(false);
105‚Üí      }
106‚Üí    }
107‚Üí    document.addEventListener("mousedown", handleClick);
108‚Üí    return () => document.removeEventListener("mousedown", handleClick);
109‚Üí  }, []);
110‚Üí
111‚Üí  // Debounced autocomplete
112‚Üí  function handleInputChange(value: string) {
113‚Üí    setSearchQuery(value);
114‚Üí    setSearchError(null);
115‚Üí    setActiveIndex(-1);
116‚Üí
117‚Üí    if (debounceRef.current) clearTimeout(debounceRef.current);
118‚Üí
119‚Üí    if (value.trim().length < 2) {
120‚Üí      setPredictions([]);
121‚Üí      setShowDropdown(false);
122‚Üí      return;
123‚Üí    }
124‚Üí
125‚Üí    debounceRef.current = setTimeout(async () => {
126‚Üí      try {
127‚Üí        const results = await api.placesAutocomplete(value.trim());
128‚Üí        setPredictions(results);
129‚Üí        setShowDropdown(results.length > 0);
130‚Üí      } catch {
131‚Üí        setPredictions([]);
132‚Üí        setShowDropdown(false);
133‚Üí      }
134‚Üí    }, 250);
135‚Üí  }
136‚Üí
137‚Üí  async function selectPrediction(prediction: PlacePrediction) {
138‚Üí    setSearchQuery(prediction.label);
139‚Üí    setShowDropdown(false);
140‚Üí    setPredictions([]);
141‚Üí    setSearchError(null);
142‚Üí
143‚Üí    try {
144‚Üí      const result = await api.geocode({ place_id: prediction.place_id });
145‚Üí      const loc = { lat: result.lat, lng: result.lng };
146‚Üí      setCoords(loc);
147‚Üí      setLocationLabel(result.label);
148‚Üí      await fetchStores(loc);
149‚Üí    } catch {
150‚Üí      setSearchError("Could not find that location. Try a different search.");
151‚Üí    }
152‚Üí  }
153‚Üí
154‚Üí  async function handleSubmit(e: React.FormEvent) {
155‚Üí    e.preventDefault();
156‚Üí    const q = searchQuery.trim();
157‚Üí    if (q.length < 2) return;
158‚Üí
159‚Üí    setShowDropdown(false);
160‚Üí    setPredictions([]);
161‚Üí    setSearchError(null);
162‚Üí
163‚Üí    try {
164‚Üí      const result = await api.geocode({ q });
165‚Üí      const loc = { lat: result.lat, lng: result.lng };
166‚Üí      setCoords(loc);
167‚Üí      setLocationLabel(result.label);
168‚Üí      await fetchStores(loc);
169‚Üí    } catch {
170‚Üí      setSearchError("Could not find that location. Try a city or zip code.");
171‚Üí    }
172‚Üí  }
173‚Üí
174‚Üí  function handleKeyDown(e: React.KeyboardEvent) {
175‚Üí    if (!showDropdown || predictions.length === 0) return;
176‚Üí
177‚Üí    if (e.key === "ArrowDown") {
178‚Üí      e.preventDefault();
179‚Üí      setActiveIndex((prev) =>
180‚Üí        prev < predictions.length - 1 ? prev + 1 : 0,
181‚Üí      );
182‚Üí    } else if (e.key === "ArrowUp") {
