31‚Üí  if (diffDays < 30) return `${diffDays} days ago`;
32‚Üí  const diffMonths = Math.floor(diffDays / 30);
33‚Üí  if (diffMonths === 1) return "1 month ago";
34‚Üí  if (diffMonths < 12) return `${diffMonths} months ago`;
