updateOrderStatus(token, storeId, orderId, status, opts?)
confirmPickup(token, storeId, orderId, pickupCode)
lookupByCode(token, storeId, pickupCode)
getPayoutSummary(token, storeId, pickupWindowId)

// Subscription Plans
listSubscriptionPlans(token, storeId)
createSubscriptionPlan(token, storeId, input)
updateSubscriptionPlan(token, storeId, planId, input)
generateNextCycle(token, storeId, planId)

// Subscriptions
listSubscriptions(token, storeId)
cancelSubscription(token, storeId, subscriptionId)

// Box Previews
listBoxPreviews(token, storeId, planId)
createBoxPreview(token, storeId, planId, input)
deleteBoxPreview(token, storeId, planId, previewId)

// Geo & Places
