import type { Metadata } from "next";
import Link from "next/link";
import Image from "next/image";
import { api } from "@/lib/api";
import type { ReviewsResponse, BoxPreviewPublic } from "@/lib/api";
import { SubscribeForm } from "@/components/subscribe-form";
import { RefreshButton } from "@/components/refresh-button";
import { cadenceLabel, formatMoney } from "@/lib/ui";
import { ReviewSummary, ReviewCard } from "@/components/review-card";

export async function generateMetadata({
  params,
}: {
  params: Promise<{ planId: string }>;
}): Promise<Metadata> {
  const { planId } = await params;
  try {
    const plan = await api.getSubscriptionPlan(planId);
    const title = `${plan.title} ‚Äî Local Roots`;
    const description = plan.description
      ? `${plan.description.slice(0, 150)} ‚Äî subscribe and pick up fresh food.`
      : `Subscribe to ${plan.title} and pick up fresh, local food.`;
    return {
      title,
      description,
      openGraph: { title, description, type: "website" },
    };
  } catch {
    return { title: "Farm Box ‚Äî Local Roots" };
  }
}

function formatPickupDate(isoDate: string, timezone: string) {
  const start = new Date(isoDate);
  return new Intl.DateTimeFormat("en-US", {
    timeZone: timezone || "UTC",
    weekday: "short",
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  }).format(start);
}

export default async function BoxPlanPage({
  params,
}: {
  params: Promise<{ planId: string }>;
}) {
  const { planId } = await params;

  let plan: Awaited<ReturnType<typeof api.getSubscriptionPlan>> | null = null;
  let error: string | null = null;
  let reviews: ReviewsResponse | null = null;

  try {
    plan = await api.getSubscriptionPlan(planId);
  } catch (e) {
    error = e instanceof Error ? e.message : "Unknown error";
  }

  let storeName = "Store";
  let preview: BoxPreviewPublic | null = null;
  if (plan) {
    try {
      const store = await api.getStore(plan.store_id);
      storeName = store.name;
    } catch {
      // Fall back to "Store" if fetch fails
    }
    try {
      reviews = await api.listStoreReviews(plan.store_id);
    } catch {
      // Reviews are non-critical; continue without them
    }
    try {
      preview = await api.getLatestBoxPreview(planId);
    } catch {
      // Preview is non-critical; continue without it
    }
  }

  return (
    <div className="grid gap-6">
      {plan ? (
        <nav className="text-sm text-[color:var(--lr-muted)]">
          <Link href={`/stores/${plan.store_id}`} className="hover:text-[color:var(--lr-ink)] hover:underline">
            {storeName}
          </Link>
          <span className="mx-1">&rarr;</span>
          <span className="text-[color:var(--lr-ink)] font-medium">{plan.title}</span>
        </nav>
      ) : null}
      <div className="grid gap-1">
        <h1 className="text-3xl font-semibold tracking-tight text-[color:var(--lr-ink)]">
          {plan ? plan.title : "Box"}
        </h1>
        <p className="text-sm text-[color:var(--lr-muted)]">
          {plan ? `${cadenceLabel(plan.cadence)} ¬∑ ${formatMoney(plan.price_cents)} per box` : ""}
        </p>
      </div>

      {error ? (
        <div className="lr-card lr-card-strong p-6">
          <p className="text-sm font-medium text-[color:var(--lr-ink)]">
            Could not load this box
          </p>
          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">{error}</p>
          <RefreshButton />
        </div>
      ) : null}

      {plan?.image_url ? (
        <div className="lr-card lr-card-strong overflow-hidden">
          <div className="relative aspect-[16/9] w-full">
            <Image
              src={plan.image_url}
              alt={plan.title}
              fill
              className="object-cover"
              sizes="(max-width: 1024px) 100vw, 1024px"
              priority
            />
          </div>
        </div>
      ) : null}

      {preview ? (
        <section className="lr-card lr-card-strong p-6 grid gap-3">
          <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
            What&apos;s in the box
          </h2>
          {preview.body ? (
            <p className="text-sm text-[color:var(--lr-muted)] whitespace-pre-line">
              {preview.body}
            </p>
          ) : null}
          {preview.photo_url ? (
            <div className="relative aspect-[16/9] w-full overflow-hidden rounded-lg">
              <Image
                src={preview.photo_url}
                alt="This week's box"
                fill
                className="object-cover"
                sizes="(max-width: 1024px) 100vw, 1024px"
              />
            </div>
          ) : null}
          <p className="text-xs text-[color:var(--lr-muted)] opacity-70">
            For the {preview.cycle_date} pickup
          </p>
        </section>
      ) : null}

      {plan ? (
        <div className="grid gap-6 lg:grid-cols-2">
          <section className="lr-card lr-card-strong p-6">
            <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
              Pickup details
            </h2>
            <div className="mt-2 flex items-start gap-4">
              <p className="flex-1 text-sm text-[color:var(--lr-muted)]">
                {plan.pickup_location.label ? `${plan.pickup_location.label} ¬∑ ` : ""}
                {plan.pickup_location.address1}, {plan.pickup_location.city},{" "}
                {plan.pickup_location.region} {plan.pickup_location.postal_code}
              </p>
              {plan.pickup_location.photo_url ? (
                <div className="relative h-[70px] w-[100px] flex-shrink-0 overflow-hidden rounded-lg">
                  <Image
                    src={plan.pickup_location.photo_url}
                    alt={plan.pickup_location.label ?? "Pickup spot"}
                    fill
                    className="object-cover"
                    sizes="100px"
                  />
                </div>
              ) : null}
            </div>
            {reviews && reviews.review_count > 0 ? (
              <div className="mt-3">
                <ReviewSummary avgRating={reviews.avg_rating} reviewCount={reviews.review_count} />
              </div>
            ) : null}
            <div className="mt-4 grid gap-2 text-sm text-[color:var(--lr-muted)]">
              <div className="lr-chip rounded-2xl px-4 py-3">
                <div className="text-xs font-semibold uppercase tracking-wide opacity-80">
                  Next pickup
                </div>
                <div className="mt-1 font-semibold text-[color:var(--lr-ink)]">
                  {formatPickupDate(plan.next_start_at, plan.pickup_location.timezone)}
                </div>
              </div>
              <div className="lr-chip rounded-2xl px-4 py-3">
                <div className="text-xs font-semibold uppercase tracking-wide opacity-80">
                  Policies
                </div>
                <div className="mt-1">
                  Skip before cutoff. Seller cancels: full refund.
                </div>
              </div>
            </div>
          </section>

          <SubscribeForm plan={plan} />
        </div>
      ) : null}

      {reviews && reviews.reviews.length > 0 ? (
        <section className="grid gap-3">
          <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
            Recent reviews
          </h2>
          <div className="grid gap-3">
            {reviews.reviews.slice(0, 3).map((r) => (
              <ReviewCard key={r.id} review={r} />
            ))}
          </div>
        </section>
      ) : null}
    </div>
  );
}

package scheduler

import (
	"context"
	"log"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"

	v1 "github.com/paretoimproved/local-roots/backend/internal/api/v1"
	"github.com/paretoimproved/local-roots/backend/internal/email"
	"github.com/paretoimproved/local-roots/backend/internal/payments/stripepay"
)

// Start launches in-process cron jobs. It blocks until ctx is cancelled.
// Call this in a goroutine from main.go.
//
// Jobs:
//   - Billing authorization: every 30 minutes
//   - Pickup reminders: every 30 minutes (offset by 15 min)
func Start(ctx context.Context, db *pgxpool.Pool, stripeClient *stripepay.Client, emailClient *email.Client, frontendURL string) {
	billingTicker := time.NewTicker(30 * time.Minute)
	reminderTicker := time.NewTicker(30 * time.Minute)
	defer billingTicker.Stop()
	defer reminderTicker.Stop()

	log.Printf("scheduler: started (billing=30m, reminders=30m)")

	// Run billing immediately on startup, then on tick.
	go runBilling(ctx, db, stripeClient)

	// Delay reminders by 15 min to stagger with billing.
	go func() {
		select {
		case <-time.After(15 * time.Minute):
			runReminders(ctx, db, emailClient, frontendURL)
		case <-ctx.Done():
		}
	}()

	for {
		select {
		case <-ctx.Done():
			log.Printf("scheduler: stopped")
			return
		case <-billingTicker.C:
			go runBilling(ctx, db, stripeClient)
		case <-reminderTicker.C:
			go runReminders(ctx, db, emailClient, frontendURL)
		}
	}
}

func runBilling(ctx context.Context, db *pgxpool.Pool, stripeClient *stripepay.Client) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("scheduler: billing panic: %v", r)
		}
	}()

	if db == nil || stripeClient == nil || !stripeClient.Enabled() {
		return
	}

	result, err := v1.RunBillingAuthorization(ctx, db, stripeClient)
	if err != nil {
		log.Printf("scheduler: billing error: %v", err)
		return
	}
	log.Printf("scheduler: billing candidates=%d authorized=%d failed=%d until=%s",
		result.Candidates, result.Authorized, result.Failed, result.Until.Format(time.RFC3339))
}

func runReminders(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client, frontendURL string) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("scheduler: reminders panic: %v", r)
		}
	}()

	if db == nil || emailClient == nil || !emailClient.Enabled() {
		return
	}

	result, err := v1.RunPickupReminders(ctx, db, emailClient, frontendURL)
	if err != nil {
		log.Printf("scheduler: reminders error: %v", err)
		return
	}
	log.Printf("scheduler: reminders candidates=%d sent=%d",
		result.Candidates, result.Sent)
}

