package v1

import (
	"context"
	"fmt"
	"log"
	"strings"

	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/paretoimproved/local-roots/backend/internal/email"
)

// ReengagementResult holds the outcome of a lapsed-subscriber reengagement run.
type ReengagementResult struct {
	Candidates int
	Sent       int
}

// RunReengagement finds active subscribers who haven't picked up in 2+ cycles
// (based on plan cadence) and sends them a nudge email. Idempotent: only sends
// once per 14 days per subscription (last_reengagement_email_at).
func RunReengagement(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client, frontendURL string) (ReengagementResult, error) {
	if db == nil {
		return ReengagementResult{}, fmt.Errorf("database not configured")
	}
	if emailClient == nil || !emailClient.Enabled() {
		return ReengagementResult{}, fmt.Errorf("email not configured")
	}

	rows, err := db.Query(ctx, `
		SELECT s.id::text, s.buyer_email, s.buyer_name, sp.title as plan_title,
		       sp.cadence, st.name as store_name, st.id::text as store_id
		FROM subscriptions s
		JOIN subscription_plans sp ON sp.id = s.plan_id
		JOIN stores st ON st.id = s.store_id
		WHERE s.status = 'active'
		  AND (s.last_reengagement_email_at IS NULL
		       OR s.last_reengagement_email_at < NOW() - INTERVAL '14 days')
		  AND NOT EXISTS (
		    SELECT 1 FROM orders o
		    WHERE o.subscription_id = s.id
		      AND o.status = 'picked_up'
		      AND o.picked_up_at > NOW() - (
		        CASE sp.cadence
		          WHEN 'weekly' THEN INTERVAL '14 days'
		          WHEN 'biweekly' THEN INTERVAL '28 days'
		          WHEN 'monthly' THEN INTERVAL '60 days'
		        END
		      )
		  )
		LIMIT 50
	`)
	if err != nil {
		return ReengagementResult{}, err
	}
	defer rows.Close()

	type candidate struct {
		subID      string
		buyerEmail string
		buyerName  string
		planTitle  string
		cadence    string
		storeName  string
		storeID    string
	}

	var candidates []candidate
	for rows.Next() {
		var c candidate
		if err := rows.Scan(&c.subID, &c.buyerEmail, &c.buyerName, &c.planTitle, &c.cadence, &c.storeName, &c.storeID); err != nil {
			return ReengagementResult{}, err
		}
		candidates = append(candidates, c)
	}
	if rows.Err() != nil {
		return ReengagementResult{}, rows.Err()
	}

	sent := 0
	baseURL := strings.TrimRight(frontendURL, "/")

	for _, c := range candidates {
		storeURL := baseURL + "/stores/" + c.storeID

		subj, body := email.LapsedSubscriberNudge(c.storeName, c.planTitle, storeURL)
		if err := emailClient.Send(c.buyerEmail, subj, body); err != nil {
			log.Printf("reengagement: failed to send to %s (sub=%s): %v", c.buyerEmail, c.subID, err)
			continue
		}

		if _, err := db.Exec(ctx, `
			UPDATE subscriptions SET last_reengagement_email_at = NOW() WHERE id = $1::uuid
		`, c.subID); err != nil {
			log.Printf("reengagement: failed to update last_reengagement_email_at for sub=%s: %v", c.subID, err)
		}

		sent++
	}

	return ReengagementResult{
		Candidates: len(candidates),
		Sent:       sent,
	}, nil
}

// ReviewPromptResult holds the outcome of a post-pickup review prompt run.
type ReviewPromptResult struct {
	Candidates int
	Sent       int
}

// RunReviewPrompts finds orders picked up 2+ hours ago that have no review and
// no prior prompt, then sends the buyer a review request email.
func RunReviewPrompts(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client, frontendURL string) (ReviewPromptResult, error) {
	if db == nil {
		return ReviewPromptResult{}, fmt.Errorf("database not configured")
	}
	if emailClient == nil || !emailClient.Enabled() {
		return ReviewPromptResult{}, fmt.Errorf("email not configured")
	}

	rows, err := db.Query(ctx, `
		SELECT o.id::text, o.buyer_email, o.store_id::text, o.buyer_token,
		       COALESCE(sp.title, o.product_title, 'Order') as box_title,
		       st.name as store_name
		FROM orders o
		LEFT JOIN subscription_plans sp ON sp.id = o.plan_id
		JOIN stores st ON st.id = o.store_id
		WHERE o.status = 'picked_up'
		  AND o.picked_up_at < NOW() - INTERVAL '2 hours'
		  AND o.review_prompt_sent_at IS NULL
		  AND NOT EXISTS (
		    SELECT 1 FROM reviews r WHERE r.order_id = o.id
		  )
		LIMIT 50
	`)
	if err != nil {
		return ReviewPromptResult{}, err
	}
	defer rows.Close()

	type candidate struct {
		orderID    string
		buyerEmail string
		storeID    string
		buyerToken string
		boxTitle   string
		storeName  string
	}

	var candidates []candidate
	for rows.Next() {
		var c candidate
		if err := rows.Scan(&c.orderID, &c.buyerEmail, &c.storeID, &c.buyerToken, &c.boxTitle, &c.storeName); err != nil {
			return ReviewPromptResult{}, err
		}
		candidates = append(candidates, c)
	}
	if rows.Err() != nil {
		return ReviewPromptResult{}, rows.Err()
	}

	sent := 0
	baseURL := strings.TrimRight(frontendURL, "/")

	for _, c := range candidates {
		reviewURL := baseURL + "/orders/" + c.orderID + "?t=" + c.buyerToken

		subj, body := email.PostPickupReviewPrompt(c.storeName, c.boxTitle, reviewURL)
		if err := emailClient.Send(c.buyerEmail, subj, body); err != nil {
			log.Printf("review-prompt: failed to send to %s (order=%s): %v", c.buyerEmail, c.orderID, err)
			continue
		}

		if _, err := db.Exec(ctx, `
			UPDATE orders SET review_prompt_sent_at = NOW() WHERE id = $1::uuid
		`, c.orderID); err != nil {
			log.Printf("review-prompt: failed to update review_prompt_sent_at for order=%s: %v", c.orderID, err)
		}

		sent++
	}

	return ReviewPromptResult{
		Candidates: len(candidates),
		Sent:       sent,
	}, nil
}

package v1

import (
	"context"
	"fmt"
	"log"
	"strings"

	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/paretoimproved/local-roots/backend/internal/payments/stripepay"
)

// TransferRetryResult holds the outcome of a transfer retry run.
type TransferRetryResult struct {
	Candidates int
	Retried    int
	Failed     int
}

// RunTransferRetry finds orders whose seller transfer failed and retries them
// (up to 3 attempts). Safe to call from both the HTTP handler and the
// in-process scheduler.
func RunTransferRetry(ctx context.Context, db *pgxpool.Pool, sc *stripepay.Client) (TransferRetryResult, error) {
	if db == nil {
		return TransferRetryResult{}, fmt.Errorf("database not configured")
	}
	if sc == nil || !sc.Enabled() {
		return TransferRetryResult{}, fmt.Errorf("payments not configured")
	}

	rows, err := db.Query(ctx, `
		SELECT o.id::text, o.store_id::text, o.stripe_payment_intent_id,
		       o.total_cents, o.transfer_retry_count
		FROM orders o
		WHERE o.transfer_attempted_at IS NOT NULL
		  AND o.stripe_transfer_id IS NULL
		  AND o.transfer_error IS NOT NULL
		  AND o.transfer_retry_count < 3
		  AND o.status IN ('picked_up', 'no_show')
		  AND o.refunded_at IS NULL
		LIMIT 20
	`)
	if err != nil {
		return TransferRetryResult{}, err
	}
	defer rows.Close()

	type candidate struct {
		orderID    string
		storeID    string
		piID       string
		totalCents int
		retryCount int
	}

	var cands []candidate
	for rows.Next() {
		var c candidate
		if err := rows.Scan(&c.orderID, &c.storeID, &c.piID, &c.totalCents, &c.retryCount); err != nil {
			return TransferRetryResult{}, err
		}
		cands = append(cands, c)
	}
	if rows.Err() != nil {
		return TransferRetryResult{}, rows.Err()
	}

	retried := 0
	failed := 0

	for _, c := range cands {
		// Look up store's Stripe Connect account.
		var connectAccountID *string
		var connectStatus string
		if err := db.QueryRow(ctx, `
			SELECT stripe_account_id, stripe_account_status
			FROM stores
			WHERE id = $1::uuid
		`, c.storeID).Scan(&connectAccountID, &connectStatus); err != nil {
			log.Printf("transfer-retry: store lookup failed for order %s: %v", c.orderID, err)
			failed++
			updateTransferError(ctx, db, c.orderID, fmt.Sprintf("store lookup: %v", err))
			continue
		}

		if connectAccountID == nil || strings.TrimSpace(*connectAccountID) == "" || connectStatus != "active" {
			log.Printf("transfer-retry: skipping order %s ‚Äî store %s account not active", c.orderID, c.storeID)
			failed++
			updateTransferError(ctx, db, c.orderID, "store connect account not active")
			continue
		}

		chargeID, err := sc.GetChargeIDFromPaymentIntent(ctx, c.piID)
		if err != nil {
			log.Printf("transfer-retry: get charge failed for order %s: %v", c.orderID, err)
			failed++
			updateTransferError(ctx, db, c.orderID, fmt.Sprintf("get charge: %v", err))
			continue
		}

		transferID, err := sc.CreateTransfer(ctx, c.totalCents, *connectAccountID, chargeID, "retry-"+c.orderID)
		if err != nil {
			log.Printf("transfer-retry: transfer failed for order %s: %v", c.orderID, err)
			failed++
			updateTransferError(ctx, db, c.orderID, fmt.Sprintf("transfer: %v", err))
			continue
		}

		_, _ = db.Exec(ctx, `
			UPDATE orders
			SET stripe_transfer_id = $1,
			    transfer_error = NULL,
			    transfer_attempted_at = NOW()
			WHERE id = $2::uuid
		`, transferID, c.orderID)

		log.Printf("transfer-retry: success for order %s (transfer %s)", c.orderID, transferID)
		retried++
	}

	return TransferRetryResult{
		Candidates: len(cands),
		Retried:    retried,
		Failed:     failed,
	}, nil
}

func updateTransferError(ctx context.Context, db *pgxpool.Pool, orderID string, errMsg string) {
	_, _ = db.Exec(ctx, `
		UPDATE orders
		SET transfer_retry_count = transfer_retry_count + 1,
		    transfer_error = $1,
		    transfer_attempted_at = NOW()
		WHERE id = $2::uuid
	`, errMsg, orderID)
}

package v1

import (
	"context"
	"fmt"
	"log"

	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/paretoimproved/local-roots/backend/internal/email"
)

// MilestoneResult holds the outcome of a milestone email run.
type MilestoneResult struct {
	Candidates int
	Sent       int
}

// RunMilestoneEmails finds subscribers who have hit cumulative pickup milestones
// (5, 10, 25, 50) and sends a celebration email. Idempotent: only sends once
// per subscription + milestone pair via the milestone_emails table.
func RunMilestoneEmails(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client) (MilestoneResult, error) {
	if db == nil {
		return MilestoneResult{}, fmt.Errorf("database not configured")
	}
	if emailClient == nil || !emailClient.Enabled() {
		return MilestoneResult{}, fmt.Errorf("email not configured")
	}

	rows, err := db.Query(ctx, `
		SELECT s.id as subscription_id, s.buyer_email, s.buyer_name,
		       st.name as store_name, st.id as store_id,
		       COUNT(o.id) as pickup_count
		FROM subscriptions s
		JOIN stores st ON st.id = s.store_id
		JOIN orders o ON o.subscription_id IN (
		    SELECT s2.id FROM subscriptions s2
		    WHERE s2.buyer_email = s.buyer_email AND s2.store_id = s.store_id
		)
		WHERE s.status = 'active'
		  AND o.status = 'picked_up'
		GROUP BY s.id, s.buyer_email, s.buyer_name, st.name, st.id
		HAVING COUNT(o.id) IN (5, 10, 25, 50)
		LIMIT 100
	`)
	if err != nil {
		return MilestoneResult{}, err
	}
	defer rows.Close()

	type candidate struct {
		subscriptionID string
		buyerEmail     string
		buyerName      string
		storeName      string
		storeID        string
		pickupCount    int
	}

	var candidates []candidate
	for rows.Next() {
		var c candidate
		var namePtr *string
		if err := rows.Scan(&c.subscriptionID, &c.buyerEmail, &namePtr, &c.storeName, &c.storeID, &c.pickupCount); err != nil {
			return MilestoneResult{}, err
		}
		if namePtr != nil {
			c.buyerName = *namePtr
		}
		candidates = append(candidates, c)
	}
	if rows.Err() != nil {
		return MilestoneResult{}, rows.Err()
	}

	sent := 0
	for _, c := range candidates {
		milestone := fmt.Sprintf("%d", c.pickupCount)

		// Check if we already sent this milestone for this subscription.
		var exists bool
		err := db.QueryRow(ctx, `
			SELECT EXISTS(
				SELECT 1 FROM milestone_emails
				WHERE subscription_id = $1::uuid AND milestone = $2
			)
		`, c.subscriptionID, milestone).Scan(&exists)
		if err != nil {
			log.Printf("milestone: error checking existing record sub=%s milestone=%s: %v", c.subscriptionID, milestone, err)
			continue
		}
		if exists {
			continue
		}

		subj, body := email.MilestoneCelebration(c.buyerName, c.storeName, milestone)
		if err := emailClient.Send(c.buyerEmail, subj, body); err != nil {
			log.Printf("milestone: error sending email to=%s sub=%s milestone=%s: %v", c.buyerEmail, c.subscriptionID, milestone, err)
			continue
		}

		_, err = db.Exec(ctx, `
			INSERT INTO milestone_emails (subscription_id, milestone) VALUES ($1::uuid, $2)
		`, c.subscriptionID, milestone)
		if err != nil {
			log.Printf("milestone: error recording sent email sub=%s milestone=%s: %v", c.subscriptionID, milestone, err)
			continue
		}

		sent++
	}

	return MilestoneResult{
		Candidates: len(candidates),
		Sent:       sent,
	}, nil
}

package v1

import (
	"context"
	"fmt"
	"log"

	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/paretoimproved/local-roots/backend/internal/email"
)

// DigestResult holds the outcome of a seller weekly digest run.
type DigestResult struct {
	Candidates int
	Sent       int
}

// RunSellerDigest sends a weekly digest email to each seller with an active store
// that has at least one active subscription. Includes active subscriber count,
// pickups this week, and revenue this week.
func RunSellerDigest(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client) (DigestResult, error) {
	if db == nil {
		return DigestResult{}, fmt.Errorf("database not configured")
	}
	if emailClient == nil || !emailClient.Enabled() {
		return DigestResult{}, fmt.Errorf("email not configured")
	}

	rows, err := db.Query(ctx, `
		SELECT DISTINCT st.id::text, st.name, u.email as seller_email
		FROM stores st
		JOIN users u ON u.id = st.user_id
		WHERE st.is_active = true
		  AND EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.store_id = st.id AND sub.status = 'active')
	`)
	if err != nil {
		return DigestResult{}, err
	}
	defer rows.Close()

	type store struct {
		storeID     string
		storeName   string
		sellerEmail string
	}

	var stores []store
	for rows.Next() {
		var s store
		if err := rows.Scan(&s.storeID, &s.storeName, &s.sellerEmail); err != nil {
			return DigestResult{}, err
		}
		stores = append(stores, s)
	}
	if rows.Err() != nil {
		return DigestResult{}, rows.Err()
	}

	sent := 0
	for _, s := range stores {
		var activeSubs int
		var pickupsWeek int
		var revenueWeek int

		err := db.QueryRow(ctx, `
			SELECT
			  (SELECT COUNT(*) FROM subscriptions WHERE store_id = $1::uuid AND status = 'active') as active_subs,
			  (SELECT COUNT(*) FROM orders WHERE store_id = $1::uuid AND status = 'picked_up' AND picked_up_at >= NOW() - INTERVAL '7 days') as pickups_week,
			  (SELECT COALESCE(SUM(total_cents), 0) FROM orders WHERE store_id = $1::uuid AND status = 'picked_up' AND picked_up_at >= NOW() - INTERVAL '7 days') as revenue_week
		`, s.storeID).Scan(&activeSubs, &pickupsWeek, &revenueWeek)
		if err != nil {
			log.Printf("digest: error querying metrics for store=%s: %v", s.storeID, err)
			continue
		}

		activeSubsStr := fmt.Sprintf("%d", activeSubs)
		pickupsStr := fmt.Sprintf("%d", pickupsWeek)
		revenueFormatted := fmt.Sprintf("$%.2f", float64(revenueWeek)/100)

		subj, body := email.SellerWeeklyDigest(s.storeName, activeSubsStr, pickupsStr, revenueFormatted)
		if err := emailClient.Send(s.sellerEmail, subj, body); err != nil {
			log.Printf("digest: error sending email to=%s store=%s: %v", s.sellerEmail, s.storeID, err)
			continue
		}

		sent++
	}

	return DigestResult{
		Candidates: len(stores),
		Sent:       sent,
	}, nil
}

